// Merge Sort implementation
function mergeSort(arr) {
    if (arr.length <= 1) return arr;
    const mid = Math.floor(arr.length / 2);
    const left = mergeSort(arr.slice(0, mid));
    const right = mergeSort(arr.slice(mid));
    return merge(left, right);
}
function merge(l, r) {
    const result = [];
    let i = 0, j = 0;
    while (i < l.length && j < r.length) {
        if (l[i] <= r[j]) result.push(l[i++]);
        else result.push(r[j++]);
    }
    return [...result, ...l.slice(i), ...r.slice(j)];
}

// Activity Selection — max non-overlapping intervals
function maxActivities(intervals) {
    intervals.sort((a, b) => a[1] - b[1]);  // Sort by end time
    let count = 1, end = intervals[0][1];
    for (let i = 1; i < intervals.length; i++) {
        if (intervals[i][0] >= end) {
            count++;
            end = intervals[i][1];
        }
    }
    return count;
}

// Jump Game — can reach last index?
function canJump(nums) {
    let maxReach = 0;
    for (let i = 0; i < nums.length; i++) {
        if (i > maxReach) return false;
        maxReach = Math.max(maxReach, i + nums[i]);
    }
    return true;
}
